import{c as e,Q as n,j as r,m as o}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"从 Prompt 到 Harness：如何理解 LLM Engineering","description":"","frontmatter":{"url":"https://x.com/yan5xu/status/2059117572826746979","author":"@yan5xu","author_bio":"🤖 AI 野生研究员 | ex @ManusAI_HQ & @hey_im_monica","author_name":"yan5xu","fetched":"2026-05-27T00:00:00.000Z","published":"2026-05-26T00:00:00.000Z","score":8.45,"tags":["harness-engineering","context-engineering","prompt-engineering","llm-agents","agentic-systems"],"tweet_id":2059117572826747000,"type":"article"},"headers":[],"relativePath":"research/tweets/2026-05-26-@yan5xu-746979.md","filePath":"research/tweets/2026-05-26-@yan5xu-746979.md","lastUpdated":1779896515000}'),a={name:"research/tweets/2026-05-26-@yan5xu-746979.md"};function i(s,t,g,l,p,h){return n(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="从-prompt-到-harness-如何理解-llm-engineering" tabindex="-1">从 Prompt 到 Harness：如何理解 LLM Engineering <a class="header-anchor" href="#从-prompt-到-harness-如何理解-llm-engineering" aria-label="Permalink to &quot;从 Prompt 到 Harness：如何理解 LLM Engineering&quot;">​</a></h1><p><strong>Author</strong>: @yan5xu（AI 野生研究员，ex ManusAI / Monica） <strong>Published</strong>: 2026-05-26 <strong>URL</strong>: <a href="https://x.com/yan5xu/status/2059117572826746979" target="_blank" rel="noreferrer">https://x.com/yan5xu/status/2059117572826746979</a><strong>Type</strong>: Twitter Article</p><p><strong>Engagement</strong>: 204 likes · 384 bookmarks · 43,250 views · 31 RT · 2 replies <strong>Score</strong>: 8.45 / 10</p><hr><h2 id="_5-維度評分" tabindex="-1">5 維度評分 <a class="header-anchor" href="#_5-維度評分" aria-label="Permalink to &quot;5 維度評分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>說明</th></tr></thead><tbody><tr><td>A. 可行動性 ×0.3</td><td>9</td><td>直接對應 harness 設計決策：shift-feedback-left、失敗模式倒推邊界、per-session 約束</td></tr><tr><td>B. 創新性 ×0.2</td><td>8</td><td>螺旋積層框架清晰，「harness ≠ runtime」的邊界劃定值得收錄</td></tr><tr><td>C. 證據品質 ×0.2</td><td>8</td><td>Epsilla 42%→78%、LangChain &gt;60% diff、Stripe/Anthropic/OpenAI 三案例</td></tr><tr><td>D. 技術深度 ×0.15</td><td>9</td><td>structural tests 強制架構、JSON 比 MD 更難被 agent 篡改等機制細節</td></tr><tr><td>E. 泛化性 ×0.15</td><td>8</td><td>螺旋框架可應用於任何 LLM 工程演化分析</td></tr></tbody></table><p><strong>整合建議</strong>：分數 8.45 &gt; 6 → 建議整合。核心框架（螺旋三圈 + harness 定義）適合補充至 <code>.claude/rules/</code> 或 <code>.claude/skills/</code> 的 harness engineering 相關文件。</p><hr><h2 id="核心主張" tabindex="-1">核心主張 <a class="header-anchor" href="#核心主張" aria-label="Permalink to &quot;核心主張&quot;">​</a></h2><p>LLM 工程從 Prompt Engineering → Context Engineering → Harness Engineering，不是線性替代而是<strong>螺旋積層</strong>：每一圈包含前一圈作為基礎設施。每次演化都由兩個力量同步驅動：模型更強了、人敢多放手一點。</p><p><strong>Harness Engineering 的定義</strong>：</p><blockquote><p>為 agent 構建運行環境的工程實踐。第一步是<strong>放手</strong>：給 agent 工具和反馈通道，讓它自主獲取信息、自主判斷。第二步是<strong>上保險</strong>：給 agent 框定能力邊界，確保自主運行不失控。</p></blockquote><hr><h2 id="全文內容" tabindex="-1">全文內容 <a class="header-anchor" href="#全文內容" aria-label="Permalink to &quot;全文內容&quot;">​</a></h2><p>虽然 LLM 应用的历史始于 2022 年 ChatGPT 问世，但工程实践已经从 Prompt Engineering，经历 Context Engineering，发展到如今的 Harness Engineering。想要彻底理解 Harness Engineering，就必须回到前面两者，理解为什么旧的做法不够用了，新的做法解决了什么，又卡在了哪里。</p><p><strong>TL;DR</strong></p><ul><li>Prompt Engineering：任务是静态的，人手工优化单次输入。局限：解决不了多步任务。</li><li>Context Engineering：任务是动态展开的，程序按预设规则编排步与步之间的信息流转。局限：人硬编码的规则限制了模型的自主能动性。</li><li>Harness Engineering：模型足够强了，放手让它自主获取反馈、自主判断，同时框定能力边界作为保险。</li></ul><hr><h2 id="prompt-engineering-对着🔮许愿的时代" tabindex="-1">Prompt Engineering：对着🔮许愿的时代 <a class="header-anchor" href="#prompt-engineering-对着🔮许愿的时代" aria-label="Permalink to &quot;Prompt Engineering：对着🔮许愿的时代&quot;">​</a></h2><p>2022 年底 ChatGPT 上线，所有人第一次面对同一个问题：怎么让这个东西给出有用的回答？</p><p>这个时期出了不少今天看来相当魔幻的事情。有人发现在 prompt 末尾加一句&quot;这对我的职业生涯非常重要&quot;，模型的输出质量就会提升。有人发现说&quot;请一步步思考&quot;比直接问答案靠谱得多。</p><p>这些尝试逐渐沉淀出一套实践：Few-shot、Chain-of-Thought、Role assignment、Output format。</p><p><strong>Prompt Engineering 的局限</strong>：本质上是单次任务的优化。然后模型开始支持工具调用，任务从&quot;问一个问题&quot;变成了&quot;跑一个流程&quot;。瓶颈从&quot;怎么问&quot;移到了&quot;给它看什么&quot;。</p><hr><h2 id="context-engineering-当任务不再是一句话能说清的" tabindex="-1">Context Engineering：当任务不再是一句话能说清的 <a class="header-anchor" href="#context-engineering-当任务不再是一句话能说清的" aria-label="Permalink to &quot;Context Engineering：当任务不再是一句话能说清的&quot;">​</a></h2><p>真实世界的任务很少是静态的。修一个 bug 的完整过程：搜日志 → 定位模块 → 读代码 → 修函数 → LSP 报 type error → 改调用方 → 跑测试 → 发现边界情况。每一步的输出决定了下一步该做什么、该看什么。</p><p><strong>Context Engineering 要回答的问题</strong>：</p><ul><li>上一步执行完了，它的结果怎么流入下一步的 context？</li><li>环境产生了反馈（LSP 报错、测试失败），怎么注入？</li><li>对话历史越来越长，哪些压缩、哪些保留？</li><li>外部检索回来的信息，在哪一步注入、注入多少？</li></ul><p>Cursor 是典型的 Context Engineering 产品：根据正在编辑的文件动态检索相关代码注入，不是把所有文件都塞进 context。</p><p><strong>2025-06-25 Karpathy 的定义</strong>：</p><blockquote><p>&quot;Context engineering is the delicate art and science of filling the context window with just the right information for the next step.&quot;</p></blockquote><p>注意他用的动词：filling。是<strong>外部在填</strong>，不是模型自己在找。</p><p><strong>Context Engineering 的天花板</strong>：</p><ul><li>Microsoft + Salesforce 研究：多轮对话推进，模型性能平均下降 39%，即使是最强的 o3 也从 98.1% 掉到 64.1%（context rot）</li><li>更根本的问题：当模型能力超过人类硬编码的规则时，人来做信息编排反而成了瓶颈</li></ul><hr><h2 id="harness-engineering-放手-然后上保险" tabindex="-1">Harness Engineering：放手，然后上保险 <a class="header-anchor" href="#harness-engineering-放手-然后上保险" aria-label="Permalink to &quot;Harness Engineering：放手，然后上保险&quot;">​</a></h2><h3 id="放手-把信息获取能力交给-agent" tabindex="-1">放手：把信息获取能力交给 agent <a class="header-anchor" href="#放手-把信息获取能力交给-agent" aria-label="Permalink to &quot;放手：把信息获取能力交给 agent&quot;">​</a></h3><p><strong>Khan 的 Prompting Inversion 证据</strong>：Sculpting 精细 prompt 技法在 gpt-4o 上准确率 97%（超过 CoT 的 93%），但在 gpt-5 上反转了（CoT 96%，Sculpting 降到 94%）。模型越强，人类精心设计的技巧反而成了约束。</p><p><strong>对比 Context Engineering vs Harness Engineering</strong>：</p><ul><li>Lovable（Context Engineering）：程序自动捕获 LSP 报错，机械地塞进下一轮 context，agent 被动接收</li><li>Stripe Minions（Harness Engineering）：agent 拥有 lint/测试/代码搜索工具，自己决定什么时候用、用哪个</li></ul><h3 id="上保险-框定能力边界" tabindex="-1">上保险：框定能力边界 <a class="header-anchor" href="#上保险-框定能力边界" aria-label="Permalink to &quot;上保险：框定能力边界&quot;">​</a></h3><p>Sandbox 隔离、CI 轮数限制、文件权限限制、架构约束（违反模块边界直接 fail）。能力边界不是对模型的不信任，而是对非确定性系统的工程纪律。</p><h3 id="什么不算-harness" tabindex="-1">什么不算 Harness <a class="header-anchor" href="#什么不算-harness" aria-label="Permalink to &quot;什么不算 Harness&quot;">​</a></h3><p>状态持久化、compaction、session 续接、跨 context window 的记忆管理 → 这些是 agent <strong>runtime</strong> 该做的事，不是 harness。Harness 关心的是 agent 跑的时候能不能自主获取反馈、会不会被约束住。</p><hr><h2 id="三大案例" tabindex="-1">三大案例 <a class="header-anchor" href="#三大案例" aria-label="Permalink to &quot;三大案例&quot;">​</a></h2><h3 id="stripe-minions" tabindex="-1">Stripe Minions <a class="header-anchor" href="#stripe-minions" aria-label="Permalink to &quot;Stripe Minions&quot;">​</a></h3><p>每周合并超过 1000 个 PR，全部 agent 写的，人只做 review。</p><p><strong>放手</strong>：Agent 可以跑 lint、跑测试、通过 Sourcegraph 搜索代码、通过 MCP 查阅内部文档和 ticket。设计原则：&quot;shift feedback left&quot;，5 秒内完成本地 lint 检查。</p><p><strong>上保险</strong>：跑在隔离 devbox，不能访问生产环境和外网；最多跑两轮 CI；MCP 连接 400+ 内部工具，但每个 agent 只能访问经过筛选的子集。</p><p><strong>注意</strong>：Stripe 的按子目录自动加载 rule files → 这是 <strong>context engineering</strong>（程序预设），不是 harness。</p><h3 id="anthropic-claude-agent-sdk-实验" tabindex="-1">Anthropic Claude Agent SDK 实验 <a class="header-anchor" href="#anthropic-claude-agent-sdk-实验" aria-label="Permalink to &quot;Anthropic Claude Agent SDK 实验&quot;">​</a></h3><p>让 agent 自主构建完整 web 应用（claude.ai 克隆）。</p><p><strong>三种失败模式 → 对应保险</strong>：</p><table tabindex="0"><thead><tr><th>失败模式</th><th>保险机制</th></tr></thead><tbody><tr><td>一口气做太多</td><td>每个 session 只做一个 feature（硬约束）</td></tr><tr><td>过早宣布完成</td><td>feature_list.json 全标 failing，agent 只能改 passes 字段（用 JSON 不用 MD，结构更难被篡改）</td></tr><tr><td>假装测试通过</td><td>必须用 Puppeteer 做端到端验证</td></tr></tbody></table><p><strong>设计原则</strong>：能力边界从失败模式倒推出来，不是凭空画线。</p><h3 id="openai-codex-团队" tabindex="-1">OpenAI Codex 团队 <a class="header-anchor" href="#openai-codex-团队" aria-label="Permalink to &quot;OpenAI Codex 团队&quot;">​</a></h3><p>3-7 人，5 个月，100 万行代码，1500 个 PR。</p><p><strong>Ryan Lopopolo 总结</strong>：</p><blockquote><p>&quot;Agents aren&#39;t hard; the Harness is hard.&quot;</p></blockquote><p><strong>设计亮点</strong>：定期&quot;垃圾回收&quot;——持续扫描整个代码库，发现架构 drift 自动创建修复任务给 agent。</p><p><strong>上保险</strong>：分层架构由 structural tests 强制执行（不是靠 prompt 说&quot;请不要违反架构&quot;）。</p><p><strong>最终结论</strong>：</p><blockquote><p>&quot;Our most difficult challenges now center on designing environments, feedback loops, and control systems.&quot;</p></blockquote><hr><h2 id="定量验证" tabindex="-1">定量验证 <a class="header-anchor" href="#定量验证" aria-label="Permalink to &quot;定量验证&quot;">​</a></h2><ul><li><strong>Epsilla 实验</strong>：同一个模型、同一个 prompt、同一份数据，只换 harness 配置 → 任务成功率从 <strong>42% → 78%</strong></li><li><strong>LangChain Terminal Bench 2.0</strong>：同一个 Opus 4.6 模型，不同 harness 下 solve rate 差异<strong>超过 60%</strong></li></ul><hr><h2 id="回头看-一个螺旋的三圈" tabindex="-1">回头看：一个螺旋的三圈 <a class="header-anchor" href="#回头看-一个螺旋的三圈" aria-label="Permalink to &quot;回头看：一个螺旋的三圈&quot;">​</a></h2><p>每一次演化都由三件事同步驱动：</p><ol><li>模型更强了一点，能做更长更复杂的任务</li><li>人敢多放手一点，从全程在场到只看结果</li><li>新的可靠性问题暴露，催生新的工程实践来兜底</li></ol><p><strong>螺旋积层</strong>：前一圈不消失，变成基础设施。Harness 里还在跑 context engineering pipeline，pipeline 里还在写精心设计的 system prompt。</p><p><strong>下一圈已露出</strong>：</p><ul><li><strong>Eval</strong>：agent 跑完了，结果到底好不好？LLM-as-judge 有 bias，&quot;评估评估的系统&quot;是递归问题。Cisco/Splunk 收购 Galileo 信号明显</li><li><strong>Governance</strong>：多 agent 互相认证、审计、权限管理。NIST 启动 AI Agent Standards Initiative，计划 2026-Q4 发布 Agent Interoperability Profile 初版</li></ul><hr><h2 id="信息来源-作者列举" tabindex="-1">信息来源（作者列举） <a class="header-anchor" href="#信息来源-作者列举" aria-label="Permalink to &quot;信息来源（作者列举）&quot;">​</a></h2><p><strong>核心定义</strong>：</p><ul><li>Andrej Karpathy, Context Engineering 定义, Twitter/X, 2025.06.25</li><li>Birgitta Böckeler, Harness Engineering for Coding Agent Users, martinfowler.com, 2026.04.02</li><li>Ryan Lopopolo, Harness Engineering: Leveraging Codex in an Agent-First World, openai.com, 2026.02.11</li><li>LangChain, The Anatomy of an Agent Harness, blog.langchain.com, 2026.03.10</li></ul><p><strong>产品案例</strong>：</p><ul><li>Stripe Engineering, Minions, stripe.dev, 2026.02.09</li><li>Anthropic, Effective Harnesses for Long-Running Agents, anthropic.com, 2025.11.26</li><li>Anthropic, Effective Context Engineering for AI Agents, anthropic.com, 2025.09.29</li></ul><p><strong>研究数据</strong>：</p><ul><li>Khan, Prompting Inversion, arXiv, 2025</li><li>Laban et al., LLMs Get Lost In Multi-Turn Conversation, Microsoft + Salesforce, 2025</li><li>Meincke, Mollick et al., The Decreasing Value of Chain of Thought, arXiv, 2025</li><li>Epsilla, Harness Engineering: Evolution from Prompt to Context to Autonomous Agents, 2026</li></ul>',82)])])}const c=e(a,[["render",i]]);export{u as __pageData,c as default};
